// zone-redundant.bicep — spread across all three AZs in the region
param location string = resourceGroup().location
param appName string

// Standard Load Balancer — required for zone-redundant backend pools
resource lb 'Microsoft.Network/loadBalancers@2023-09-01' = {
  name: '${appName}-lb'
  location: location
  sku: { name: 'Standard' }  // Standard SKU required for AZ support (not Basic)
  properties: {
    frontendIPConfigurations: [{
      name: 'frontend'
      properties: { publicIPAddress: { id: pip.id } }
    }]
  }
}

// VM Scale Set across all three AZs
resource vmss 'Microsoft.Compute/virtualMachineScaleSets@2024-03-01' = {
  name: '${appName}-vmss'
  location: location
  zones: ['1', '2', '3']  // deploy instances in all three AZs
  sku: { name: 'Standard_D2s_v5', capacity: 3 }
  properties: {
    upgradePolicy: { mode: 'Automatic' }
    virtualMachineProfile: {
      storageProfile: {
        imageReference: {
          publisher: 'Canonical'
          offer: '0001-com-ubuntu-server-jammy'
          sku: '22_04-lts-gen2'
          version: 'latest'
        }
      }
    }
  }
}
